/**
 * Simple Markdown Parser Component
 * Since we can't use external libraries like react-markdown without importing,
 * we'll implement a basic one to handle bold, bullet points, and paragraphs.
 */
const ReactMarkdown: React.FC<{ content: string }> = ({ content }) => {
  const parseContent = (text: string) => {
    // Basic regex-based parsing for structured Gemini output
    const lines = text.split('\n');
    return lines.map((line, i) => {
      // Bullet points
      if (line.trim().startsWith('* ') || line.trim().startsWith('- ')) {
        return (
          <li key={i} className="ml-4 mb-1">
            {renderLine(line.replace(/^[*|-]\s/, ''))}
          </li>
        );
      }
      // Headlines
      if (line.startsWith('### ')) {
        return <h4 key={i} className="text-base font-bold mt-4 mb-2 text-slate-800">{line.replace('### ', '')}</h4>;
      }
      // Paragraphs
      return line.trim() ? <p key={i} className="mb-3">{renderLine(line)}</p> : <div key={i} className="h-2"></div>;
    });
  };

  const renderLine = (text: string) => {
    // Handle bold
    const parts = text.split(/(\*\*.*?\*\*)/);
    return parts.map((part, i) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={i} className="font-bold text-slate-900">{part.slice(2, -2)}</strong>;
      }
      return part;
    });
  };

  return <div>{parseContent(content)}</div>;
};

