            </div>
            <div>
              <h2 className="text-sm font-bold text-slate-800">Symptom Checker & Support</h2>
              <div className="flex items-center gap-1.5">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                <span className="text-[11px] font-medium text-slate-500 uppercase tracking-tight">Gemini 3.0 Pro Active</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400 hover:text-slate-600">
              <ArrowPathIcon className="w-5 h-5" />
            </button>
          </div>
        </header>

        {/* Message List */}
        <div 
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-4 lg:p-8 space-y-6 bg-slate-50"
        >
          <div className="max-w-3xl mx-auto space-y-8 pb-12">
            {messages.map((message) => (
              <div 
                key={message.id} 
                className={`flex ${message.role === Role.USER ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}
              >
                <div className={`flex flex-col max-w-[85%] lg:max-w-[80%] ${message.role === Role.USER ? 'items-end' : 'items-start'}`}>
                  <div className={`
                    p-4 rounded-2xl shadow-sm leading-relaxed
                    ${message.role === Role.USER 
                      ? 'bg-emerald-600 text-white rounded-tr-none' 
                      : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none'
                    }
                  `}>
                    {message.isThinking ? (
                      <div className="flex gap-1 py-1">
                        <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce"></div>
                        <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce delay-75"></div>
                        <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce delay-150"></div>
                      </div>
                    ) : (
                      <div className="prose prose-sm prose-slate max-w-none prose-p:leading-relaxed prose-li:my-1">
                        <ReactMarkdown content={message.content} />
                      </div>
                    )}
                  </div>

                  {message.sources && message.sources.length > 0 && (
                    <div className="mt-3 flex flex-wrap gap-2">
                      {message.sources.map((source, idx) => (
                        <a 
                          key={idx}
                          href={source.uri}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="flex items-center gap-1.5 px-3 py-1 bg-white border border-slate-200 rounded-full text-[10px] font-bold text-slate-500 hover:border-emerald-300 hover:text-emerald-600 transition-all shadow-sm"
                        >
                          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                          </svg>
                          {source.title.substring(0, 30)}...
                        </a>
                      ))}
                    </div>
                  )}

                  <span className="text-[10px] text-slate-400 mt-2 font-semibold">
                    {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                </div>
              </div>
            ))}

            {/* Empty State / Suggestions */}
            {messages.length < 3 && !isTyping && (
              <div className="pt-8 border-t border-slate-200 animate-in fade-in slide-in-from-top-4 duration-700">
                <div className="flex items-center gap-2 mb-4 px-1 text-slate-500">
                  <ChatBubbleLeftRightIcon className="w-5 h-5 text-emerald-500" />
                  <h3 className="text-xs font-bold uppercase tracking-widest">Common Health Concerns</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {SUGGESTED_PROMPTS.map((prompt, i) => (
                    <button
                      key={i}
                      onClick={() => handleSendMessage(prompt.text)}
                      className="text-left p-4 bg-white border border-slate-200 rounded-2xl hover:border-emerald-500 hover:shadow-md hover:shadow-emerald-50/50 transition-all group"
                    >
                      <span className="block text-[11px] font-bold text-emerald-600 uppercase tracking-tight mb-1">{prompt.label}</span>
                      <p className="text-slate-600 text-xs font-medium leading-normal group-hover:text-slate-800">{prompt.text}</p>
                    </button>
                  ))}
                </div>
              </div>
            )}

            {error && (
              <div className="p-4 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-xs font-bold flex items-center gap-3">
                <ExclamationTriangleIcon className="w-5 h-5" />
                {error}
              </div>
            )}
          </div>
        </div>

        {/* Input Area */}
        <div className="p-4 lg:p-6 bg-white border-t border-slate-200">
          <div className="max-w-3xl mx-auto">
            <form onSubmit={handleSubmit} className="relative group">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Describe your symptoms or ask a health question..."
                className="w-full pl-6 pr-14 py-4 bg-slate-50 focus:bg-white border-2 border-transparent focus:border-emerald-500 rounded-2xl outline-none text-slate-800 transition-all shadow-sm font-medium placeholder:text-slate-400"
                disabled={isTyping}
              />
              <button 
                type="submit"
                disabled={isTyping || !input.trim()}
                className={`
                  absolute right-2 top-2 bottom-2 w-12 flex items-center justify-center rounded-xl transition-all
                  ${isTyping || !input.trim() 
                    ? 'bg-slate-200 text-slate-400' 
                    : 'bg-emerald-600 text-white hover:bg-emerald-700 shadow-lg shadow-emerald-200 active:scale-95'
                  }
                `}
              >
                {isTyping ? (
                  <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                ) : (
                  <PaperAirplaneIcon className="w-5 h-5 -rotate-45" />
                )}
              </button>
            </form>
            <div className="flex items-center justify-center gap-4 mt-3">
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">
                🔒 Privacy Protected
              </p>
              <span className="text-slate-200">•</span>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">
                🏥 AI Support Only
              </p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

/**
 * Simple Markdown Parser Component
 * Since we can't use external libraries like react-markdown without importing,
 * we'll implement a basic one to handle bold, bullet points, and paragraphs.
 */
const ReactMarkdown: React.FC<{ content: string }> = ({ content }) => {
  const parseContent = (text: string) => {
    // Basic regex-based parsing for structured Gemini output
    const lines = text.split('\n');
    return lines.map((line, i) => {
      // Bullet points
      if (line.trim().startsWith('* ') || line.trim().startsWith('- ')) {
        return (
          <li key={i} className="ml-4 mb-1.5 list-disc text-slate-700">
            {renderLine(line.replace(/^[*|-]\s/, ''))}
          </li>
        );
      }
      // Headlines
      if (line.startsWith('### ')) {
        return <h4 key={i} className="text-sm font-bold mt-4 mb-2 text-slate-800 uppercase tracking-tight border-l-2 border-emerald-500 pl-2">{line.replace('### ', '')}</h4>;
      }
      // Paragraphs
      return line.trim() ? <p key={i} className="mb-4 text-slate-700 leading-relaxed">{renderLine(line)}</p> : <div key={i} className="h-2"></div>;
    });
  };

  const renderLine = (text: string) => {
    // Handle bold
    const parts = text.split(/(\*\*.*?\*\*)/);
    return parts.map((part, i) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={i} className="font-bold text-slate-900">{part.slice(2, -2)}</strong>;
      }
      return part;
    });
  };

  return <div>{parseContent(content)}</div>;
};

export default App;
